// All 8 falsy values:
false        // the boolean false
0            // the number zero
-0           // negative zero (rare but falsy)
0n           // BigInt zero
''           // empty string (also "" or ``)
null         // intentional absence
undefined    // not yet assigned
NaN          // not a number

// Quick test — these all print 'falsy':
[false, 0, -0, 0n, '', null, undefined, NaN].forEach(v => {
  if (!v) console.log(String(v), '→ falsy');
});

// 1. if statements
const name = '';
if (name) {
  console.log('has name'); // skipped — empty string is falsy
}

// 2. Ternary operator
const label = name ? name : 'Guest'; // 'Guest' because name is falsy

// 3. Logical AND &&
const result = name && name.toUpperCase(); // false — short-circuits because name is falsy

// 4. Logical OR ||
const display = name || 'Guest'; // 'Guest' — uses right side because name is falsy

// 5. Logical NOT !
console.log(!name);  // true  — falsy becomes true
console.log(!!name); // false — double negation converts to actual boolean

// || returns the first truthy operand, or the last operand if all are falsy
'hello' || 'world'  // 'hello'  (left is truthy, short-circuits)
false || 'world'    // 'world'  (left is falsy, returns right)
0 || 42             // 42       (left is falsy, returns right)
null || undefined   // undefined (both falsy, returns last)

// Common pattern: default values
const username = inputValue || 'Guest';
const port = config.port || 3000;

// React renders: false → nothing, null → nothing, undefined → nothing
// React renders: 0 → the character '0' (a common trap!)

function Notifications({ count }) {
  return (
    <div>
      {/* ❌ Bug: renders '0' when count is 0 */}
      {count && <Badge>{count}</Badge>}

      {/* ✅ Correct: explicit boolean — renders nothing when count is 0 */}
      {count > 0 && <Badge>{count}</Badge>}

      {/* ✅ Also correct: ternary is always safe */}
      {count > 0 ? <Badge>{count}</Badge> : null}
    </div>
  );
}

// || is useful for optional props with string/object defaults
function Greeting({ name, color }) {
  const displayName = name || 'Guest';     // 'Guest' if name is falsy
  const textColor = color || 'black';      // 'black' if color not provided
  return <p style={{ color: textColor }}>Hello, {displayName}!</p>;
}

// But use ?? when 0 or '' are valid values:
function Score({ value }) {
  const display = value ?? 'N/A'; // keeps 0; only falls back for null/undefined
  return <span>{display}</span>;
}

function UserProfile({ user, isLoading }) {
  // null and undefined are falsy — great for guarding
  if (!user) return <p>No user selected</p>;
  if (isLoading) return <p>Loading...</p>;

  return (
    <div>
      <h2>{user.name}</h2>
      {/* Optional field: only render bio section if bio is truthy */}
      {user.bio && <p className="bio">{user.bio}</p>}
    </div>
  );
}

// ❌ Renders visible '0' when items.length is 0
return <div>{items.length && <List items={items} />}</div>;

// ✅ Fix: compare to a boolean explicitly
return <div>{items.length > 0 && <List items={items} />}</div>;
// ✅ Or convert to boolean with !!
return <div>{!!items.length && <List items={items} />}</div>;

// ❌ Wrong: 0 is a valid score but || replaces it
const score = userScore || 'No score'; // 'No score' when score is 0!

// ✅ Use ?? to preserve 0 and ''
const score = userScore ?? 'No score'; // 'No score' only if null/undefined

// ❌ Empty array is truthy — this always runs
const items = [];
if (items) {
  renderList(items); // runs even when there's nothing to render
}

// ✅ Check length instead
if (items.length > 0) {
  renderList(items);
}

// Two ways to convert any value to a real boolean:
Boolean(value)  // explicit, readable
!!value         // double negation — common shorthand in React props

// Example: a prop that expects a boolean
<Modal isOpen={!!selectedItem} />
// If selectedItem is null/undefined → false; if it's an object → true

// filter(Boolean) removes all falsy values from an array:
const values = [1, 0, 'hello', '', null, undefined, false, 42];
const truthy = values.filter(Boolean);
console.log(truthy); // [1, 'hello', 42]
